import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"标准账户出金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"withdrawal/standard-account-guide.md","filePath":"zh-CN/withdrawal/standard-account-guide.md"}'),i={name:"withdrawal/standard-account-guide.md"};function l(o,t,h,n,c,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="标准账户出金" tabindex="-1">标准账户出金 <a class="header-anchor" href="#标准账户出金" aria-label="Permalink to &quot;标准账户出金&quot;">​</a></h1><p>标准账户出金支持的币种、方式、到账时间、各币种手续费及限制条件。</p><h2 id="重要提示" tabindex="-1">重要提示 <a class="header-anchor" href="#重要提示" aria-label="Permalink to &quot;重要提示&quot;">​</a></h2><p>长桥已于 2025 年 5 月 31 日停止长桥标准账户的服务。长桥标准账户目前仅支持卖出、出金或转出操作。</p><h2 id="支持币种" tabindex="-1">支持币种 <a class="header-anchor" href="#支持币种" aria-label="Permalink to &quot;支持币种&quot;">​</a></h2><p>港元（HKD）、美元（USD）、澳元（AUD）、人民币（CNY）、马来西亚令吉（MYR）、新加坡元（SGD）、英镑（GBP）、欧元（EUR）、日元（JPY）</p><h2 id="支持出金方式" tabindex="-1">支持出金方式 <a class="header-anchor" href="#支持出金方式" aria-label="Permalink to &quot;支持出金方式&quot;">​</a></h2><p>电汇（WIRE）、网银转账、FPS 转数快</p><h2 id="到账时间" tabindex="-1">到账时间 <a class="header-anchor" href="#到账时间" aria-label="Permalink to &quot;到账时间&quot;">​</a></h2><p>预计 1-3 个交易日</p><h2 id="手续费" tabindex="-1">手续费 <a class="header-anchor" href="#手续费" aria-label="Permalink to &quot;手续费&quot;">​</a></h2><p>长桥按笔收取手续费，各币种标准如下：</p><table tabindex="0"><thead><tr><th>币种</th><th>手续费</th></tr></thead><tbody><tr><td>HKD</td><td>65 HKD / 笔</td></tr><tr><td>USD</td><td>7.5 USD / 笔</td></tr><tr><td>AUD</td><td>10 AUD / 笔</td></tr><tr><td>CNY</td><td>50 CNH / 笔</td></tr><tr><td>MYR</td><td>30 MYR / 笔</td></tr><tr><td>SGD</td><td>5 SGD / 笔</td></tr><tr><td>GBP</td><td>5.5 GBP / 笔</td></tr><tr><td>EUR</td><td>7 EUR / 笔</td></tr><tr><td>JPY</td><td>1,200 JPY / 笔</td></tr><tr><td>汇出行、中转行及收款行可能额外收取费用，最终到账金额以实际为准。</td><td></td></tr></tbody></table><h3 id="特殊收费说明" tabindex="-1">特殊收费说明 <a class="header-anchor" href="#特殊收费说明" aria-label="Permalink to &quot;特殊收费说明&quot;">​</a></h3><ul><li>非新加坡本地银行卡及新加坡本地银行出金美元：4 USD / 笔（支票方式）</li><li>SGD 出金到新加坡本地银行卡：提现金额不得低于 1 新币</li><li>SGD 出金到香港本地银行：10 SGD / 笔</li><li>美元出金至香港本地银行：总手续费约 15 USD（上游券商 7.5 USD + 汇出行/中转行/收款行约 7-8 USD）</li><li>港币出金至不支持 FPS 的香港本地银行：65 HKD + 60-80 HKD（银行处理费用）</li><li>出金至华美银行：7.5 USD + 40 USD（银行处理费用）</li></ul><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 提取资金，选择币种、收款银行、输入金额后提交。</p><h2 id="支持账户类型与出金限制" tabindex="-1">支持账户类型与出金限制 <a class="header-anchor" href="#支持账户类型与出金限制" aria-label="Permalink to &quot;支持账户类型与出金限制&quot;">​</a></h2><ul><li>仅支持本人同名银行卡出金</li><li>不支持 SIB、CIB、Discover Bank 出金</li><li>不支持信用卡出金</li><li>不支持 Wise 出入金</li><li>出金收费包含券商手续费及银行费用，最终到账金额与提现金额可能有差异</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/account/标准账户停运与迁移">标准账户停运与迁移</a> — 迁移至香港或新加坡账户</li></ul>',21)])])}const b=a(i,[["render",l]]);export{p as __pageData,b as default};
